"""The Rajapinta Coherence Gate (Anti-Hallucination AI)===================================================PerceptionLab / Antti LuodeThis script proves the concept of a "Topology Detector".It listens to a continuous 1D signal. It does not try to predict or reconstruct the signal continuously.Instead, it measures the topological coherence (phase-locking) of its internal Harmonic Arms.ONLY when the geometry stabilizes into a locked attractor does it trip the Rajapinta threshold and "speak" (emit a token).This is a model of perception, not approximation."""import numpy as npimport matplotlib.pyplot as pltdef generate_signal(t_steps=2000):    """    Generates a signal that shifts between pure noise and a structured harmonic attractor.    0-500: Pure Noise (No structure)    500-1000: Harmonic Structure (k=3, k=5) buried in noise    1000-1500: Pure Noise    1500-2000: Harmonic Structure (k=4) buried in noise    """    t = np.arange(t_steps)    w0 = 0.05 # Fundamental        noise = np.random.randn(t_steps) * 1.5        # Create the true geometry    sig = noise.copy()        # Event 1 (k=3, k=5)    sig[500:1000] += 2.0 * np.sin(3 * w0 * t[500:1000])     sig[500:1000] += 1.5 * np.sin(5 * w0 * t[500:1000])        # Event 2 (k=4)    sig[1500:2000] += 2.5 * np.sin(4 * w0 * t[1500:2000])        return t, sigdef coherence_gated_arm_bank(signal, w0=0.05, n_arms=10, rajapinta_threshold=0.6):    """    A Hebbian Harmonic Arm Bank with a Coherence Gate (Rajapinta).    """    t_steps = len(signal)        # A_k: The amplitude weights of the arms    A = np.zeros(n_arms)        # To track history for plotting    A_history = np.zeros((t_steps, n_arms))    coherence_history = np.zeros(t_steps)    rajapinta_firings = np.zeros(t_steps)        # Learning parameters    lr = 0.05    decay = 0.02        for i in range(t_steps):        current_val = signal[i]        t = i                # 1. Update Arm Amplitudes (Hebbian Phase-Coherence)        for k in range(1, n_arms + 1):            idx = k - 1            # Does the input align with this harmonic arm?            phase_match = current_val * np.sin(k * w0 * t)                         # Hebbian update + Leak            A[idx] += (lr * phase_match) - (decay * A[idx])                        # Bound it            A[idx] = max(0, min(A[idx], 3.0))                        A_history[i, idx] = A[idx]                    # 2. Calculate Global Coherence (Is there a stable geometry?)        # A high sum means specific arms have locked on and stabilized.        global_coherence = np.sum(A)        coherence_history[i] = global_coherence                # 3. The Rajapinta Gate (Decision to Emit)        if global_coherence > rajapinta_threshold:            rajapinta_firings[i] = 1.0 # The system "perceives" structure                return A_history, coherence_history, rajapinta_firings# =========================================================# RUN THE EXPERIMENT# =========================================================print("Initializing Signal with hidden geometric events...")t, signal = generate_signal(2000)print("Running Coherence-Gated Arm Bank...")A_hist, coherence, firings = coherence_gated_arm_bank(signal, w0=0.05, n_arms=10, rajapinta_threshold=4.0)print("Plotting results...")fig, axs = plt.subplots(4, 1, figsize=(12, 10), sharex=True)# Plot 1: Raw Input (Looks like mostly noise)axs[0].plot(t, signal, color='gray', alpha=0.7)axs[0].set_title("1. 1D Sensory Input (Noise vs Hidden Geometry)")axs[0].set_ylabel("Amplitude")# Plot 2: The Latent Space (The Harmonic Arms learning)im = axs[1].imshow(A_hist.T, aspect='auto', cmap='magma', origin='lower', extent=[0, 2000, 1, 10])axs[1].set_title("2. Harmonic Arm State (Dynamical Vector)")axs[1].set_ylabel("Arm (k)")# Plot 3: Global Coherence (Geometry Stabilization Metric)axs[2].plot(t, coherence, color='cyan')axs[2].axhline(4.0, color='red', linestyle='--', label="Rajapinta Threshold")axs[2].set_title("3. Global Coherence (Measuring Topological Stability)")axs[2].set_ylabel("Coherence (C)")axs[2].legend()# Plot 4: The Output Token (The Rajapinta Event)axs[3].plot(t, firings, color='lime')axs[3].fill_between(t, 0, firings, color='lime', alpha=0.3)axs[3].set_title("4. Rajapinta Output (The AI 'Speaks' only when locked)")axs[3].set_ylabel("Token Fired")axs[3].set_xlabel("Time Step (t)")plt.tight_layout()plt.savefig("rajapinta_coherence_gate.png")print("Saved to rajapinta_coherence_gate.png. The breakthrough is complete.")